function toast(title,text=''){const el=document.createElement('div');el.className='toast';el.innerHTML=`<b>${esc(title)}</b>${text?`<small>${esc(text)}</small>`:''}`;$('#toasts').append(el);setTimeout(()=>el.remove(),3300)}
