function bindOpeners(scope){$$('[data-open]',scope).forEach(b=>b.onclick=e=>{if(b.dataset.dragged)return;e.stopPropagation();openApp(b.dataset.open);closeMenus()})}
function focusWindow(id){const o=state.windows.get(id);if(!o)return;const wasMin=o.el.classList.contains('minimized');o.el.classList.remove('minimized','minimizing');if(wasMin&&state.settings.animations&&o.el.animate){o.el.animate([{opacity:0,transform:'translateY(45px) scale(.82)'},{opacity:1,transform:'none'}],{duration:170,easing:'cubic-bezier(.2,.8,.2,1)'})}state.windows.forEach(x=>x.el.classList.toggle('active',x===o));o.el.style.zIndex=++state.z;state.active=id;$$('[data-task]').forEach(b=>b.classList.toggle('active',b.dataset.task===id));setTimeout(()=>$('.term-input',o.el)?.focus(),0)}
function openApp(id,opts={}){if(!apps[id])return;const existing=state.windows.get(id);if(existing){focusWindow(id);return existing}const a=apps[id],tpl=$('#windowTemplate').content.firstElementChild.cloneNode(true),body=$('.window-body',tpl);tpl.dataset.app=id;$('.window-title',tpl).textContent=a.name;const layer=$('#windowLayer'),lr=layer.getBoundingClientRect();const maxW=Math.max(340,lr.width-20),maxH=Math.max(230,lr.height-20);const w=Math.min(a.w,maxW),h=Math.min(a.h,maxH);tpl.style.width=`${w}px`;tpl.style.height=`${h}px`;const index=state.windows.size,step=18;let left=Math.round((lr.width-w)/2+(index%5)*step-36),top=Math.round((lr.height-h)/2+(index%5)*step-25);left=Math.max(10,Math.min(lr.width-w-10,left));top=Math.max(10,Math.min(lr.height-h-10,top));tpl.style.left=`${left}px`;tpl.style.top=`${top}px`;layer.append(tpl);const obj={id,el:tpl,body,app:a,max:false,restore:null};state.windows.set(id,obj);a.render(body,opts,obj);hydrateIcons(tpl);updateAllRanges(tpl);bindWindow(obj);const task=$(`[data-task="${id}"]`);if(task)task.classList.add('running');focusWindow(id);return obj}
