function bindDesktopSelection(){const d=$('#desktop'),box=$('#selectionBox');d.addEventListener('pointerdown',e=>{if(e.button!==0||e.target!==d&&e.target.id!=='wallpaper')return;$$('.desktop-icon').forEach(x=>x.classList.remove('selected'));const r=d.getBoundingClientRect(),sx=e.clientX-r.left,sy=e.clientY-r.top;let dragged=false;box.classList.remove('hidden');Object.assign(box.style,{left:sx+'px',top:sy+'px',width:'0px',height:'0px'});const move=ev=>{const x=ev.clientX-r.left,y=ev.clientY-r.top;if(Math.hypot(x-sx,y-sy)>3)dragged=true;const l=Math.min(sx,x),t=Math.min(sy,y),w=Math.abs(x-sx),h=Math.abs(y-sy);Object.assign(box.style,{left:l+'px',top:t+'px',width:w+'px',height:h+'px'});const br={left:l+r.left,top:t+r.top,right:l+w+r.left,bottom:t+h+r.top};$$('.desktop-icon').forEach(ic=>{const q=ic.getBoundingClientRect();ic.classList.toggle('selected',q.left<br.right&&q.right>br.left&&q.top<br.bottom&&q.bottom>br.top)})};const up=()=>{box.classList.add('hidden');if(!dragged)$$('.desktop-icon').forEach(x=>x.classList.remove('selected'));document.removeEventListener('pointermove',move);document.removeEventListener('pointerup',up)};document.addEventListener('pointermove',move);document.addEventListener('pointerup',up)})}
