function renderFiles(rootEl){rootEl.innerHTML=`<div class="files-app"><aside class="files-side">${folders.map(f=>`<button data-side="${f}">${icon(f==='Images'?'image':f==='Music'?'music':f==='Downloads'?'download':f==='Home'?'folder':'file')}<span>${f}</span></button>`).join('')}</aside><main class="files-main"><header class="files-toolbar"><button class="toolbar-button" data-back title="Home">${icon('chevron-down')}</button><b data-path>Home</b><span class="spacer"></span><input data-search class="field search-field" placeholder="Search..."><button class="toolbar-button" data-new title="New file">${icon('plus')}</button><button class="toolbar-button" data-upload title="Upload">${icon('upload')}</button><button class="toolbar-button" data-grid title="Grid view">${icon('grid')}</button></header><section class="file-grid"></section></main></div>`;hydrateIcons(rootEl);const grid=$('.file-grid',rootEl),path=$('[data-path]',rootEl),search=$('[data-search]',rootEl);function draw(){path.textContent=state.currentFolder;$$('[data-side]',rootEl).forEach(b=>b.classList.toggle('active',b.dataset.side===state.currentFolder));const q=search.value.trim().toLowerCase(),items=folderItems(state.currentFolder).filter(f=>f.name.toLowerCase().includes(q));grid.innerHTML=items.map(f=>`<button class="file-card" data-id="${f.id}">${fileVisual(f)}<small>${esc(f.name)}</small><em>${f.type==='folder'?'Folder':f.type==='image'?'Image':f.type==='script'?'Script':'File'}</em></button>`).join('')||`<div style="color:var(--muted);padding:20px">This folder is empty.</div>`;hydrateIcons(grid);$$('.file-card',grid).forEach(b=>{b.onclick=()=>{$$('.file-card',grid).forEach(x=>x.classList.remove('selected'));b.classList.add('selected');state.selectedFile=b.dataset.id};b.ondblclick=()=>{const f=items.find(x=>x.id===b.dataset.id);if(f.type==='folder'){state.currentFolder=f.name;draw()}else openFile(f)};b.oncontextmenu=e=>{e.preventDefault();const f=items.find(x=>x.id===b.dataset.id);showContext(e.clientX,e.clientY,[['Open',()=>openFile(f)],['Download',()=>downloadFile(f)],['Rename',()=>renameFile(f,draw)],['Duplicate',()=>duplicateFile(f,draw)],['Delete',()=>{if(confirm(`Delete ${f.name}?`)){state.files=state.files.filter(x=>x.id!==f.id);save();draw()}}]])}})}$$('[data-side]',rootEl).forEach(b=>b.onclick=()=>{state.currentFolder=b.dataset.side;draw()});search.oninput=draw;$('[data-back]',rootEl).onclick=()=>{state.currentFolder='Home';draw()};$('[data-new]',rootEl).onclick=()=>{const name=prompt('File name','untitled.txt');if(name){state.files.push({id:uid(),name,type:guessType(name),folder:state.currentFolder==='Home'?'Documents':state.currentFolder,content:''});save();draw()}};$('[data-upload]',rootEl).onclick=()=>uploadFiles(state.currentFolder==='Home'?'Downloads':state.currentFolder,draw);draw()}
function openFile(f){if(!f)return;if(f.type==='folder'){state.currentFolder=f.name;openApp('files');return}if(f.type==='image'){const o=openApp('paint');setTimeout(()=>o&&loadImageIntoPaint(o.body,f.data),30)}else if(f.type==='text'||f.type==='script')openApp('notes',{file:f});else if(f.type==='audio'){const a=new Audio(f.data);a.play();toast('Playing',f.name)}else toast('File',f.name)}
function renameFile(f,cb){const n=prompt('New name',f.name);if(n){f.name=n;f.type=guessType(n);save();cb?.()}}
function duplicateFile(f,cb){state.files.push({...f,id:uid(),name:`Copy of ${f.name}`});save();cb?.()}
function downloadFile(f){const a=document.createElement('a');a.download=f.name;a.href=f.data||URL.createObjectURL(new Blob([f.content||''],{type:f.mime||'text/plain'}));a.click()}
function readDataURL(file){return new Promise((res,rej)=>{const r=new FileReader;r.onload=()=>res(r.result);r.onerror=rej;r.readAsDataURL(file)})}
function uploadFiles(folder,cb){const p=$('#systemFilePicker');p.multiple=true;p.accept='';p.value='';p.onchange=async()=>{for(const file of p.files){const type=guessType(file.name),item={id:uid(),name:file.name,type,folder,mime:file.type,content:'',data:''};if(type==='text'||type==='script')item.content=await file.text();else item.data=await readDataURL(file);state.files.push(item)}save();cb?.();toast('Upload complete',`${p.files.length} file(s) added`)};p.click()}
function showContext(x,y,items){const c=$('#contextMenu');c.innerHTML=items.map((i,n)=>`<button data-i="${n}">${esc(i[0])}</button>`).join('');c.style.left=`${Math.min(x,innerWidth-195)}px`;c.style.top=`${Math.min(y,innerHeight-items.length*36-10)}px`;c.classList.remove('hidden');$$('button',c).forEach((b,n)=>b.onclick=()=>{items[n][1]();c.classList.add('hidden')})}
function renderTerminal(rootEl){rootEl.innerHTML=`<div class="terminal"><div class="term-output"><div class="term-line term-accent">GovencoOS Terminal</div><div class="term-line term-muted">Type help to see available commands.</div><br></div><div class="term-input-row"><span class="term-prompt"></span><input class="term-input" autocomplete="off" spellcheck="false"></div></div>`;const out=$('.term-output',rootEl),input=$('.term-input',rootEl),promptEl=$('.term-prompt',rootEl);const setPrompt=()=>promptEl.textContent=`${state.settings.name}@govencoos ~ $`;setPrompt();function line(text='',cls=''){const d=document.createElement('div');d.className=`term-line ${cls}`;d.textContent=text;out.append(d);out.scrollTop=out.scrollHeight}function html(content){const d=document.createElement('div');d.className='term-line';d.innerHTML=content;out.append(d);out.scrollTop=out.scrollHeight}async function execute(raw,fromScript=false){const commands=splitCommands(raw);for(const command of commands){const parts=parseArgs(command),cmd=(parts.shift()||'').toLowerCase();if(!cmd)continue;if(!fromScript)line(`${state.settings.name}@govencoos ~ $ ${command}`,'term-accent');const arg=parts.join(' ');switch(cmd){case'help':html(helpHtml());break;case'repeat':{const n=Math.min(100,Math.max(0,+parts.shift()||0)),sub=parts.join(' ');if(!sub)line('Usage: repeat N command','term-error');else for(let i=0;i<n;i++)await execute(sub,true);break}case'for':{const m=command.match(/^for\s+(\w+)\s+in\s+(\d+)\.\.(\d+)\s+do\s+(.+)$/i);if(!m){line('Usage: for i in 1..5 do echo $i','term-error');break}const [,v,a,b,body]=m;for(let i=+a;i<=+b&&i-+a<100;i++)await execute(body.replaceAll('$'+v,String(i)),true);break}case'clear':out.innerHTML='';break;case'echo':line(arg);break;case'date':line(new Date().toLocaleDateString());break;case'time':line(new Date().toLocaleTimeString());break;case'whoami':line(state.settings.name);break;case'hostname':line('govencoos');break;case'version':line(`GovencoOS ${VERSION}`);break;case'pwd':line('/home/'+state.settings.name);break;case'ls':line(state.files.map(f=>f.name).join('   ')||'No files');break;case'cat':{const f=findFile(arg);f?line(f.content||'[binary file]'):line('File not found','term-error');break}case'touch':if(!arg)line('Usage: touch filename','term-error');else{state.files.push({id:uid(),name:arg,type:guessType(arg),folder:'Documents',content:''});save();line(`Created ${arg}`)}break;case'mkdir':if(!arg)line('Usage: mkdir name','term-error');else{state.files.push({id:uid(),name:arg,type:'folder',folder:'Home',content:''});save();line(`Created folder ${arg}`)}break;case'rm':{const f=findFile(arg);if(f){state.files=state.files.filter(x=>x!==f);save();line(`Removed ${arg}`)}else line('File not found','term-error');break}case'rename':case'mv':{const f=findFile(parts[0]);if(f&&parts[1]){f.name=parts[1];save();line('Renamed')}else line(`Usage: ${cmd} old new`,'term-error');break}case'copy':{const f=findFile(parts[0]);if(f&&parts[1]){state.files.push({...f,id:uid(),name:parts[1]});save();line('Copied')}else line('Usage: copy source target','term-error');break}case'write':case'append':{const f=findFile(parts[0]);if(f){const txt=parts.slice(1).join(' ');f.content=cmd==='append'?`${f.content}${f.content?'\n':''}${txt}`:txt;save();line('Saved')}else line('File not found','term-error');break}case'open':if(apps[(parts[0]||'').toLowerCase()])openApp(parts[0].toLowerCase());else{const f=findFile(arg);f?openFile(f):line('App or file not found','term-error')}break;case'apps':line(Object.keys(apps).join('  '));break;case'calc':try{line(String(safeCalc(arg)))}catch{line('Invalid expression','term-error')}break;case'theme':if(wallpapers[arg]){state.settings.wallpaper=arg;state.settings.customWallpaper='';applySettings();line(`Wallpaper: ${arg}`)}else line('Themes: '+Object.keys(wallpapers).join(', '));break;case'accent':if(/^#[0-9a-f]{6}$/i.test(arg)){state.settings.accent=arg;applySettings();line('Accent changed')}else line('Usage: accent #d79a79','term-error');break;case'brightness':{const n=+arg;if(n>=55&&n<=115){state.settings.brightness=n;applySettings();line(`Brightness ${n}%`)}else line('Use 55-115','term-error');break}case'history':state.termHistory.forEach((h,i)=>line(`${i+1}  ${h}`));break;case'env':line(`USER=${state.settings.name}\nHOST=govencoos\nVERSION=${VERSION}\nSHELL=gsh`);break;case'storage':{const bytes=new Blob([JSON.stringify(state.files)]).size;line(`${state.files.length} files, ${(bytes/1024).toFixed(1)} KB used`);break}case'sysinfo':line(`GovencoOS ${VERSION}\nBrowser: ${detectBrowser()}\nScreen: ${screen.width}x${screen.height}\nFiles: ${state.files.length}\nUptime: ${uptime()}`);break;case'neofetch':html(`<div class="neofetch"><pre class="neo-g">  ██████╗ \n ██╔════╝ \n ██║  ███╗\n ██║   ██║\n ╚██████╔╝\n  ╚═════╝ </pre><div><b>${esc(state.settings.name)}@govencoos</b><span>OS: GovencoOS ${VERSION}</span><span>Browser: ${detectBrowser()}</span><span>Resolution: ${screen.width}×${screen.height}</span><span>Files: ${state.files.length}</span><span>Uptime: ${uptime()}</span><i style="background:linear-gradient(90deg,var(--accent),var(--accent2))"></i></div></div>`);break;case'uptime':line(uptime());break;case'ps':line([...state.windows.keys()].map((x,i)=>`${100+i}  ${x}`).join('\n')||'No apps');break;case'kill':{const app=[...state.windows.keys()].find((x,i)=>String(100+i)===arg||x===arg);app?(closeWindow(app),line(`Killed ${app}`)):line('Process not found','term-error');break}case'run':{const f=findFile(arg);if(f&&f.type==='script'){for(const l of f.content.split(/\r?\n/))await execute(l,true)}else line('Script not found','term-error');break}case'download':{const f=findFile(arg);f?downloadFile(f):line('File not found','term-error');break}case'upload':uploadFiles('Downloads');line('File picker opened');break;case'lock':lock();break;case'reboot':location.reload();break;case'shutdown':shutdown();break;case'clearfiles':if(confirm('Delete all local files?')){state.files=[];save();line('Files deleted')}break;default:line(`Command not found: ${cmd}`,'term-error')}}setPrompt()}input.onkeydown=e=>{if(e.key==='Enter'){const raw=input.value.trim();if(raw){state.termHistory.push(raw);state.termIndex=state.termHistory.length;execute(raw)}input.value=''}else if(e.key==='ArrowUp'){e.preventDefault();input.value=state.termHistory[Math.max(0,--state.termIndex)]||''}else if(e.key==='ArrowDown'){e.preventDefault();input.value=state.termHistory[Math.min(state.termHistory.length,++state.termIndex)]||''}};setTimeout(()=>input.focus(),0)}
function helpHtml(){const rows=[['help','Show this help'],['clear','Clear terminal'],['repeat N cmd','Repeat command'],['for i in 1..N do cmd','Simple loop'],['echo [text]','Print text'],['date / time','Current date or time'],['whoami','Current user'],['hostname','System name'],['pwd','Working directory'],['ls','List files'],['cat [file]','Read file'],['touch [file]','Create file'],['mkdir [name]','Create folder'],['rm [file]','Delete file'],['rename [a] [b]','Rename file'],['copy [a] [b]','Copy file'],['write [file] [text]','Replace content'],['append [file] [text]','Append content'],['open [app/file]','Open item'],['apps','List apps'],['calc [expr]','Calculate'],['theme [name]','Change wallpaper'],['accent [hex]','Change accent'],['brightness [55-115]','Set brightness'],['history','Command history'],['run [file.gsh]','Run script'],['download [file]','Download file'],['upload','Upload from computer'],['ps / kill','Processes'],['sysinfo','System information'],['storage','Storage usage'],['lock','Lock screen'],['reboot / shutdown','Power controls']];return `<div class="help-grid">${rows.map(r=>`<b>${esc(r[0])}</b><span>${esc(r[1])}</span>`).join('')}</div>`}
function splitCommands(s){let q=false,cur='',arr=[];for(const ch of s){if(ch==='"')q=!q;if(ch===';'&&!q){if(cur.trim())arr.push(cur.trim());cur=''}else cur+=ch}if(cur.trim())arr.push(cur.trim());return arr}
function parseArgs(s){return (s.match(/(?:[^\s"]+|"[^"]*")+/g)||[]).map(x=>x.replace(/^"|"$/g,''))}
function findFile(name){return state.files.find(f=>f.name.toLowerCase()===String(name).toLowerCase())}
function safeCalc(expr){if(!/^[0-9+\-*/().%\s]+$/.test(expr))throw Error();return Function(`"use strict";return (${expr.replace(/(\d+(?:\.\d+)?)%/g,'($1/100)')})`)()}
function uptime(){const s=Math.floor((Date.now()-state.bootTime)/1000),m=Math.floor(s/60),h=Math.floor(m/60);return `${h}h ${m%60}m ${s%60}s`}
function renderNotes(rootEl,opts={}){let file=opts.file||state.files.find(f=>f.name==='notes.txt')||{id:uid(),name:'untitled.txt',type:'text',folder:'Documents',content:''};if(!state.files.includes(file))state.files.push(file);rootEl.innerHTML=`<div class="notes"><header class="notes-toolbar"><input class="field" data-name value="${esc(file.name)}"><button class="toolbar-button" data-save title="Save">${icon('save')}</button><button class="toolbar-button" data-download title="Download">${icon('download')}</button></header><textarea spellcheck="true">${esc(file.content||'')}</textarea><footer class="statusline"><span data-status></span></footer></div>`;hydrateIcons(rootEl);const ta=$('textarea',rootEl),name=$('[data-name]',rootEl),status=$('[data-status]',rootEl);const update=()=>{const txt=ta.value;status.textContent=`${txt.length} characters · ${txt.trim()?txt.trim().split(/\s+/).length:0} words · ${txt.split(/\n/).length} lines`};ta.oninput=update;$('[data-save]',rootEl).onclick=()=>{file.name=name.value||'untitled.txt';file.type=guessType(file.name);file.content=ta.value;save();toast('Saved',file.name);buildDesktop()};$('[data-download]',rootEl).onclick=()=>{file.name=name.value||file.name;file.content=ta.value;downloadFile(file)};update()}
function renderCalculator(rootEl){rootEl.innerHTML=`<div class="calculator"><div class="calc-display"><small data-expr></small><b data-result>0</b></div><div class="calc-grid">${['C','(',')','÷','7','8','9','×','4','5','6','−','1','2','3','+','%','0','.','='].map(x=>`<button class="${'÷×−+='.includes(x)?'op':''}" data-key="${x}">${x}</button>`).join('')}</div></div>`;let expr='';const ex=$('[data-expr]',rootEl),res=$('[data-result]',rootEl);function draw(){ex.textContent=expr;try{res.textContent=expr?String(safeCalc(expr.replace(/÷/g,'/').replace(/×/g,'*').replace(/−/g,'-'))):'0'}catch{res.textContent='…'}}$$('[data-key]',rootEl).forEach(b=>b.onclick=()=>{const k=b.dataset.key;if(k==='C')expr='';else if(k==='='){try{expr=String(safeCalc(expr.replace(/÷/g,'/').replace(/×/g,'*').replace(/−/g,'-')))}catch{expr=''}}else expr+=k;draw()});draw()}
